import{_ as d,o as r,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"钙钛矿叠层电池 GW 级量产——2026 年商业化元年","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/光伏/_深化_2026-06-16_钙钛矿GW级量产.md","filePath":"电力新能源/光伏/_深化_2026-06-16_钙钛矿GW级量产.md","lastUpdated":1782226922000}'),i={name:"电力新能源/光伏/_深化_2026-06-16_钙钛矿GW级量产.md"};function e(o,t,n,h,s,g){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="钙钛矿叠层电池-gw-级量产——2026-年商业化元年" tabindex="-1">钙钛矿叠层电池 GW 级量产——2026 年商业化元年 <a class="header-anchor" href="#钙钛矿叠层电池-gw-级量产——2026-年商业化元年" aria-label="Permalink to &quot;钙钛矿叠层电池 GW 级量产——2026 年商业化元年&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>2026 年是钙钛矿光伏 GW 级量产元年。极电光能建成全球首条 GW 级单结钙钛矿产线，协鑫集成建成全球首条 GW 级叠层组件产线（量产效率 26.5%-28%，成本 0.6 元/W，较晶硅低 30%）。核心设备 100% 国产化，TCO 玻璃国产化率 95%+。国盛证券预测 2027 年全球产能超 5GW，2030 年突破 30GW。</p><h2 id="量产进展" tabindex="-1">量产进展 <a class="header-anchor" href="#量产进展" aria-label="Permalink to &quot;量产进展&quot;">​</a></h2><h3 id="极电光能——全球首条-gw-级单结钙钛矿产线" tabindex="-1">极电光能——全球首条 GW 级单结钙钛矿产线 <a class="header-anchor" href="#极电光能——全球首条-gw-级单结钙钛矿产线" aria-label="Permalink to &quot;极电光能——全球首条 GW 级单结钙钛矿产线&quot;">​</a></h3><ul><li><strong>投产时间</strong>：2025 年 2 月（江苏无锡）</li><li><strong>产能</strong>：全球已投产中产能最大、技术最先进的产线</li><li><strong>组件</strong>：2.8m² 超大尺寸，功率 450W，全面积效率 16.1%</li><li><strong>年产量</strong>：达产后约 180 万片/年</li><li><strong>技术</strong>：自主研发&quot;极创+&quot;整体解决方案</li><li><strong>定位</strong>：单结钙钛矿（非叠层），主打地面电站和分布式市场</li><li><strong>于振瑞（总裁）</strong>：2026 年是钙钛矿技术商业化突破的关键之年</li></ul><h3 id="协鑫集成——全球首条-gw-级叠层组件产线" tabindex="-1">协鑫集成——全球首条 GW 级叠层组件产线 <a class="header-anchor" href="#协鑫集成——全球首条-gw-级叠层组件产线" aria-label="Permalink to &quot;协鑫集成——全球首条 GW 级叠层组件产线&quot;">​</a></h3><ul><li><strong>投产时间</strong>：2025 年 6 月（江苏昆山）→ 2026 年 2 月全面竣工</li><li><strong>总投资</strong>：50 亿元</li><li><strong>技术路线</strong>：钙钛矿-晶硅叠层</li><li><strong>效率</strong>：量产效率 26.5%-28%（2025 年 12 月组件稳态效率 27.06% 创全球纪录）</li><li><strong>成本</strong>：组件成本约 0.6 元/W（较晶硅低 30%）</li><li><strong>良率</strong>：稳定在 98% 以上</li><li><strong>认证</strong>：全球首例基于 IEC 61730 的钙钛矿叠层光伏组件安全认证</li><li><strong>产能规划</strong>： <ul><li>2026 年：1GW → Q4 扩至 5GW</li><li>2027 年：突破 6GW</li></ul></li><li><strong>策略</strong>：GW 级量产 + 场景化示范双轮驱动</li></ul><h3 id="其他企业" tabindex="-1">其他企业 <a class="header-anchor" href="#其他企业" aria-label="Permalink to &quot;其他企业&quot;">​</a></h3><table tabindex="0"><thead><tr><th>企业</th><th>进展</th><th>预计</th></tr></thead><tbody><tr><td>仁烁光能</td><td>GW 级产线建设中</td><td>2026-2027</td></tr><tr><td>杭州柯林</td><td>GW 级产线规划</td><td>2026-2027</td></tr><tr><td>中核光电</td><td>GW 级产线规划</td><td>2026-2027</td></tr><tr><td>纤纳光电</td><td>1GW 产线</td><td>2025 下半年投产</td></tr><tr><td>京东方光能</td><td>双 IEC 认证完成</td><td>已布局</td></tr></tbody></table><h2 id="效率对比" tabindex="-1">效率对比 <a class="header-anchor" href="#效率对比" aria-label="Permalink to &quot;效率对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技术路线</th><th>量产效率</th><th>实验室效率</th><th>理论极限</th></tr></thead><tbody><tr><td>TOPCon 晶硅</td><td>25.4%-25.7%</td><td>26.5%</td><td>27.9%</td></tr><tr><td>单结钙钛矿</td><td>16%-18%</td><td>27.3%</td><td>~33%</td></tr><tr><td>钙钛矿-晶硅叠层</td><td>26.5%-28%</td><td>35.0%+</td><td>~45%</td></tr></tbody></table><p><strong>钙钛矿叠层效率 28% 已显著超越 TOPCon 的 25.7%，且差距将继续拉大。</strong></p><h2 id="供应链国产化" tabindex="-1">供应链国产化 <a class="header-anchor" href="#供应链国产化" aria-label="Permalink to &quot;供应链国产化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>环节</th><th>国产化率</th><th>代表企业</th></tr></thead><tbody><tr><td>TCO 导电玻璃</td><td>95%+</td><td>金晶科技（年产能 4500 万 m²）</td></tr><tr><td>空穴传输层材料</td><td>国产</td><td>万润股份</td></tr><tr><td>电子传输层材料</td><td>国产</td><td>万润股份</td></tr><tr><td>封装 POE 胶膜</td><td>国产</td><td>福斯特、鹿山新材</td></tr><tr><td>IZO 靶材</td><td>国产</td><td>隆华科技</td></tr><tr><td>核心设备</td><td>100%</td><td>国产供应商</td></tr><tr><td>离子交换膜</td><td>80%+</td><td>东岳集团（国产替代加速）</td></tr></tbody></table><h2 id="可靠性验证" tabindex="-1">可靠性验证 <a class="header-anchor" href="#可靠性验证" aria-label="Permalink to &quot;可靠性验证&quot;">​</a></h2><ul><li>协鑫光电：通过德国 TUV 莱茵 3 倍 IEC 标准加严老化（湿热、热循环等）</li><li>极电光能、京东方：双 IEC 认证</li><li>户外实证：首年衰减率 3.2%-4.5%</li><li>弱光发电：较晶硅提升 12%-18%</li><li>兆瓦级电站已稳定运行超一年</li></ul><h2 id="产能预测" tabindex="-1">产能预测 <a class="header-anchor" href="#产能预测" aria-label="Permalink to &quot;产能预测&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>全球产能</th><th>阶段</th></tr></thead><tbody><tr><td>2024</td><td>&lt;1GW</td><td>示范</td></tr><tr><td>2025</td><td>~3GW</td><td>元年（极电/协鑫 GW 级投产）</td></tr><tr><td>2026</td><td>~5GW</td><td>商业化突破</td></tr><tr><td>2027E</td><td>&gt;5GW</td><td>爆发期</td></tr><tr><td>2030E</td><td>&gt;30GW</td><td>规模化</td></tr></tbody></table><h2 id="投资逻辑" tabindex="-1">投资逻辑 <a class="header-anchor" href="#投资逻辑" aria-label="Permalink to &quot;投资逻辑&quot;">​</a></h2><ul><li><strong>叠层是确定性方向</strong>：效率碾压晶硅且仍在提升，成本低 30%</li><li><strong>国产化壁垒已成</strong>：100% 核心设备国产化，不受进口限制</li><li><strong>2026 下半年进入主流市场</strong>：协鑫规模化量产后成本持续下探</li><li><strong>关注主线</strong>： <ol><li>头部量产企业（协鑫集成、极电光能）</li><li>关键材料国产化（金晶科技、万润股份、福斯特）</li><li>设备国产化</li></ol></li></ul><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>长期稳定性尚未完全验证（户外运行数据 &lt; 3 年）</li><li>大面积组件效率与实验室效率差距仍大</li><li>晶硅技术（TOPCon/HJT/BC）仍在快速迭代，竞争激烈</li><li>钙钛矿含铅问题可能面临环保监管</li><li>产能过剩风险：若需求不及预期，2027 年可能出现产能过剩</li></ol><hr><p><em>来源：科技日报、苏州政府网、亚太光伏、国盛证券、极电光能/协鑫官方</em><em>更新：2026-06-16</em></p>',25)])])}const _=d(i,[["render",e]]);export{u as __pageData,_ as default};
